# frozen_string_literal: true

# This is the 'merged.json' file, generated by running csv-to-popolo
# against the 'merged.csv' file, which we then post-process into an
# EveryPolitician-specific version

require 'json'

module Everypolitician
  module GeneratedFile
    class MergedJSON
      def initialize(pathname)
        @pathname = pathname
      end

      # TODO: move all the transformation code to here.
      def json
        raw
      end

      private

      attr_reader :pathname

      def raw
        @raw ||= JSON.parse(pathname.read, symbolize_names: true)
      end
    end
  end
end
